class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        def dfs(num, n, k):
            if n == 0:
                res.append(num)
                return
            for i in range(10):
                if (num == 0 and i == 0) or abs(num % 10 - i) == k:
                    dfs(num * 10 + i, n - 1, k)
        res = []
        dfs(0, n, k)
        return res
